import{_ as r,o,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"💡 光通訊追蹤日報 — 2026-05-18（週一）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-18.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-18.md"}'),e={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-18.md"};function l(n,t,d,s,c,h){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="💡-光通訊追蹤日報-—-2026-05-18-週一" tabindex="-1">💡 光通訊追蹤日報 — 2026-05-18（週一） <a class="header-anchor" href="#💡-光通訊追蹤日報-—-2026-05-18-週一" aria-label="Permalink to &quot;💡 光通訊追蹤日報 — 2026-05-18（週一）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-18 05:00 TST（2026-05-17 21:00 UTC） 報告類型：每日追蹤</p></blockquote><hr><h2 id="🔍-敘事延續-nvidia-搶光鴻海-cpo-broadcom-三-四代-cpo-路線圖-csp-690b-資本支出" tabindex="-1">🔍 敘事延續：NVIDIA 搶光鴻海 CPO + Broadcom 三/四代 CPO 路線圖 + CSP $690B 資本支出 <a class="header-anchor" href="#🔍-敘事延續-nvidia-搶光鴻海-cpo-broadcom-三-四代-cpo-路線圖-csp-690b-資本支出" aria-label="Permalink to &quot;🔍 敘事延續：NVIDIA 搶光鴻海 CPO + Broadcom 三/四代 CPO 路線圖 + CSP $690B 資本支出&quot;">​</a></h2><p><strong>本日核心</strong>：延續前日 NVIDIA 搶光鴻海 CPO 庫存、TSMC COUPE 量產等重大敘事。本日新增：Broadcom 公布三/四代 CPO 路線圖（200G/lane → 400G/lane）、四大雲端 2026 合計資本支出 $660-690B（近乎翻倍）、台灣光通訊個股本週關注 Nvidia 財報帶動。</p><hr><h2 id="🔴-即時指標-每日掃描" tabindex="-1">🔴 即時指標（每日掃描） <a class="header-anchor" href="#🔴-即時指標-每日掃描" aria-label="Permalink to &quot;🔴 即時指標（每日掃描）&quot;">​</a></h2><h3 id="_1-輝達-gpu-技術發布-矽光子-cpo-相關" tabindex="-1">1. 輝達 GPU 技術發布（矽光子/CPO 相關） <a class="header-anchor" href="#_1-輝達-gpu-技術發布-矽光子-cpo-相關" aria-label="Permalink to &quot;1. 輝達 GPU 技術發布（矽光子/CPO 相關）&quot;">​</a></h3><ul><li><strong>現況</strong>：NVIDIA 已「drain」鴻海全部 CPO Rack 庫存（前日更新）</li><li><strong>Quantum-X InfiniBand Switch</strong>：2026 初推出，液冷，144 ports × 800Gb/s = 115Tb/s 總頻寬</li><li><strong>Spectrum-X Photonic Ethernet</strong>：2026H2 推出，基於 Spectrum-6 晶片，SN6810 (102.4Tb/s)、SN6800 (409.6Tb/s)</li><li><strong>投資</strong>：NVIDIA 對 Coherent、Lumentum 投資 $40 億，確保激光/光學元件供應</li><li><strong>路線圖</strong>：CPO 2027 首次導入，2028 隨 Rubin/Feynman 大規模部署</li><li><strong>CPO 滲透率</strong>：2026 年 AI 資料中心僅 0.5%，2028 年預計 ~35%</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：NVIDIA (2026-01/05)、Seeking Alpha (2026-05)、Semi Engineering (2026-05)、Chiplet Marketplace (2026-05)</li></ul><h3 id="_2-博通矽光子-cpo-技術動態" tabindex="-1">2. 博通矽光子/CPO 技術動態 <a class="header-anchor" href="#_2-博通矽光子-cpo-技術動態" aria-label="Permalink to &quot;2. 博通矽光子/CPO 技術動態&quot;">​</a></h3><ul><li>🔴 <strong>路線圖更新</strong>： <ul><li><strong>第三代</strong>（2025/05 宣布）：200G/lane CPO，Tomahawk 6-Davidson switch，功耗效率比 pluggable 好 3.5 倍</li><li><strong>第四代</strong>（研發中）：400G/lane CPO</li><li><strong>量產</strong>：第二代 Tomahawk 5-Bailly 已量產，6.4 Tbps 矽光學引擎，比 pluggable 省 70% 功耗</li></ul></li><li><strong>合作</strong>：Google TPU 主要合作夥伴、Meta MTIA 定製晶片、Amazon 客戶</li><li><strong>CEO 評論</strong>：矽光子「not impacting data centers in short term, but will become a necessary path」</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：Broadcom Blog (2026-05)、IDTechEx (2026-05)、IBTimes (2026-05)</li></ul><h3 id="_3-台積電先進封裝光通訊相關" tabindex="-1">3. 台積電先進封裝光通訊相關 <a class="header-anchor" href="#_3-台積電先進封裝光通訊相關" aria-label="Permalink to &quot;3. 台積電先進封裝光通訊相關&quot;">​</a></h3><ul><li>🔴 <strong>COUPE 量產</strong>：2026 年進入量產，SoIC-X 技術整合 EIC+PIC</li><li><strong>功耗效率</strong>：比傳統堆疊降低 5-10 倍，延遲降低 10-20 倍</li><li><strong>路線圖</strong>：2025 插拔式 → 2026H2 基板層級 → 未來中介層層級</li><li><strong>CoWoS 擴產</strong>：目標 2026 年底月產 130,000 片（比 2024 底翻 4 倍）</li><li><strong>嘉義 AP7</strong>：主要先進封裝基地</li><li><strong>TSMC 預測</strong>：矽光子模組 2026 年佔光收發模組市場 &gt;50%</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：Design Reuse (2026-05)、TrendForce (2026-04)、EE Times (2026-02)</li></ul><h3 id="_4-csp-資本支出公告" tabindex="-1">4. CSP 資本支出公告 <a class="header-anchor" href="#_4-csp-資本支出公告" aria-label="Permalink to &quot;4. CSP 資本支出公告&quot;">​</a></h3><ul><li>🔴 <strong>四大雲端 2026 合計 $660-690B</strong>（近乎翻倍 YoY） <ul><li><strong>Amazon</strong>：~$200B（可能超 $230B），50%+ 由 AI 雲端驅動</li><li><strong>Google (Alphabet)</strong>：$175-185B（另有估計 $180-190B）</li><li><strong>Microsoft</strong>：$120-190B（含 $25B 記憶體晶片成本上升）</li><li><strong>Meta</strong>：$125-145B（多次上調）</li></ul></li><li><strong>含 Oracle</strong>：合計可達 $725-750B</li><li><strong>分析</strong>：AI 軍備競賽白熱化，光通訊為關鍵基礎設施</li><li><strong>查詢時間</strong>：2026-05-17</li><li>來源：Futurum Group (2026-05)、LA Times (2026-05-14)、Fast Company (2026-05)、Tom&#39;s Hardware (2026-05)</li></ul><hr><h2 id="🟡-台灣供應鏈動態" tabindex="-1">🟡 台灣供應鏈動態 <a class="header-anchor" href="#🟡-台灣供應鏈動態" aria-label="Permalink to &quot;🟡 台灣供應鏈動態&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>代號</th><th>本日動態</th><th>來源</th></tr></thead><tbody><tr><td>聯亞</td><td>3081</td><td>5/15 盤中跌停 $2,655；美系外資上調目標價至 $4,738（買進）</td><td>CNAews (2026-05)</td></tr><tr><td>光聖</td><td>6442</td><td>從高點 $2,355 回檔至 $1,895；EPS $23.46，800G/1.6T 題材</td><td>CMoney (2026-05)</td></tr><tr><td>智邦</td><td>2345</td><td>5/12 歷史新高 $2,695；Q1 營收 701 億（+64% YoY）；4 月營收 273 億創新高</td><td>CNAews (2026-05)</td></tr><tr><td>上詮</td><td>3363</td><td>無個股更新</td><td>—</td></tr><tr><td>台積電</td><td>2330</td><td>+0.7%（逆勢上漲），COUPE 技術布局激勵</td><td>TradingEconomics</td></tr><tr><td>鴻海</td><td>2317</td><td>Q1 淨利 NT$49.9B，EPS +17% YoY；CPO 出貨量 5 倍上調至 50,000</td><td>TrendForce/CNA</td></tr></tbody></table><blockquote><p><strong>說明</strong>：台股 5/15 因美股前夜下跌 + 獲利了結，TAIEX -1.39%。光通訊個股波動加大，但基本面強勁。聯亞外資分歧（目標價 $645-$4,738），反映估值爭議。</p></blockquote><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>NVIDIA (2026-01/05)</strong>：Quantum-X InfiniBand switch 115Tb/s、Spectrum-X photonic Ethernet platform</li><li><strong>Broadcom Blog (2026-05)</strong>：CPO from concept to core competency — TH5-Bailly 量產、TH6-Davidson 第三代</li><li><strong>Futurum Group (2026-05)</strong>：AI Capex 2026 — $690B infrastructure sprint</li><li><strong>TrendForce (2026-04)</strong>：TSMC COUPE 2026 量產、Samsung CPO turnkey 2029</li><li><strong>CNAews (2026-05)</strong>：聯亞外資分歧、智邦歷史新高、鴻海 CPO 50K 出貨</li></ol><hr><h2 id="🔭-產業趨勢摘要" tabindex="-1">🔭 產業趨勢摘要 <a class="header-anchor" href="#🔭-產業趨勢摘要" aria-label="Permalink to &quot;🔭 產業趨勢摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>狀態</th><th>備註</th></tr></thead><tbody><tr><td>銅退光進</td><td>🟢 加速中</td><td>NVIDIA + Broadcom 雙引擎推動</td></tr><tr><td>2026 商轉元年</td><td>🟢 重大進展</td><td>鴻海 CPO Q3 量產、TSMC COUPE 量產</td></tr><tr><td>OCI-MSA</td><td>🟡 持續觀察</td><td>—</td></tr><tr><td>美國製造回流</td><td>🟢 持續推進</td><td>Corning 3 座新廠</td></tr><tr><td>NVIDIA CPO 加速</td><td>🔴 供應極度緊張</td><td>全部庫存被拉走</td></tr><tr><td>Broadcom 3/4 代 CPO</td><td>🟢 積極推進</td><td>200G → 400G/lane</td></tr><tr><td>CSP 資本支出</td><td>🔴 翻倍成長</td><td>$660-690B（含 Oracle 可達 $750B）</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>NVIDIA (2026-01/05): Quantum-X InfiniBand switch, Spectrum-X Photonic Ethernet</li><li>Seeking Alpha (2026-05): Inside NVIDIA $4B optical strategy</li><li>Broadcom Blog (2026-05): CPO from concept to core competency</li><li>IDTechEx (2026-05): Co-packaged optics race — NVIDIA vs Broadcom</li><li>Design Reuse (2026-05): Silicon photonics race — TSMC COUPE 2026 production</li><li>TrendForce (2026-04): TSMC COUPE, Samsung CPO turnkey 2029</li><li>Futurum Group (2026-05): AI Capex 2026 — $690B infrastructure sprint</li><li>LA Times (2026-05-14): Amazon market value charges toward $3T on AI</li><li>Fast Company (2026-05): Big Tech AI spending plans reach $725B</li><li>CMoney (2026-05): 光聖回檔分析</li><li>CNAews (2026-05): 聯亞、智邦、鴻海動態</li><li>TradingEconomics (2026-05-15): TAIEX 41,172, NVIDIA -2%, TSMC +0.7%</li></ol>',28)])])}const p=r(e,[["render",l]]);export{u as __pageData,p as default};
